import { ethers } from "ethers";

const ERC20_ABI = [
  "function approve(address spender,uint256 amount) external returns (bool)",
  "function allowance(address owner,address spender) external view returns (uint256)",
  "function balanceOf(address account) external view returns (uint256)",
  "function decimals() external view returns (uint8)",
  "function symbol() external view returns (string)",
  "function name() external view returns (string)"
];

const ROUTER_ABI = [
  "function swapExactTokensForTokens(uint256 amountIn,uint256 amountOutMin,address[] calldata path,address to,uint256 deadline) external returns (uint256[] memory amounts)",
  "function getAmountsOut(uint256 amountIn,address[] calldata path) external view returns (uint256[] memory amounts)"
];

export class TokenSwapDApp {
  constructor({
    provider,
    signer,
    routerAddress,
    routerAbi = ROUTER_ABI,
    erc20Abi = ERC20_ABI
  }) {
    this.provider = provider;
    this.signer = signer;
    this.routerAddress = routerAddress;
    this.routerAbi = routerAbi;
    this.erc20Abi = erc20Abi;
    this.router = new ethers.Contract(routerAddress, routerAbi, signer || provider);
  }

  static async fromBrowserWallet(routerAddress, options = {}) {
    if (!window.ethereum) {
      throw new Error("No injected wallet found");
    }
    const browserProvider = new ethers.BrowserProvider(window.ethereum);
    await browserProvider.send("eth_requestAccounts", []);
    const signer = await browserProvider.getSigner();
    return new TokenSwapDApp({
      provider: browserProvider,
      signer,
      routerAddress,
      ...options
    });
  }

  getTokenContract(tokenAddress, withSigner = true) {
    return new ethers.Contract(
      tokenAddress,
      this.erc20Abi,
      withSigner && this.signer ? this.signer : this.provider
    );
  }

  async getAddress() {
    if (!this.signer) {
      throw new Error("Signer required");
    }
    return await this.signer.getAddress();
  }

  async getTokenMeta(tokenAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    const [name, symbol, decimals] = await Promise.all([
      token.name().catch(() => ""),
      token.symbol().catch(() => ""),
      token.decimals().catch(() => 18)
    ]);
    return { name, symbol, decimals: Number(decimals) };
  }

  async getBalance(tokenAddress, account) {
    const token = this.getTokenContract(tokenAddress, false);
    return await token.balanceOf(account);
  }

  async getAllowance(tokenAddress, owner, spender = this.routerAddress) {
    const token = this.getTokenContract(tokenAddress, false);
    return await token.allowance(owner, spender);
  }

  async needsApproval(tokenAddress, owner, amountIn, spender = this.routerAddress) {
    const allowance = await this.getAllowance(tokenAddress, owner, spender);
    return allowance < amountIn;
  }

  async approveMax(tokenAddress, spender = this.routerAddress) {
    if (!this.signer) {
      throw new Error("Signer required");
    }
    const token = this.getTokenContract(tokenAddress, true);
    const tx = await token.approve(spender, ethers.MaxUint256);
    const receipt = await tx.wait();
    return { tx, receipt };
  }

  async ensureApproval(tokenAddress, amountIn, spender = this.routerAddress) {
    const owner = await this.getAddress();
    const required = BigInt(amountIn);
    const allowance = await this.getAllowance(tokenAddress, owner, spender);
    if (allowance >= required) {
      return { approved: false, allowance };
    }
    const result = await this.approveMax(tokenAddress, spender);
    return {
      approved: true,
      allowanceBefore: allowance,
      ...result
    };
  }

  async getQuote(amountIn, path) {
    return await this.router.getAmountsOut(amountIn, path);
  }

  async swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    amountOutMin,
    to,
    deadlineSeconds = 1200,
    path
  }) {
    if (!this.signer) {
      throw new Error("Signer required");
    }

    const recipient = to || (await this.getAddress());
    const swapPath = path || [tokenIn, tokenOut];
    const now = Math.floor(Date.now() / 1000);
    const deadline = now + deadlineSeconds;

    const approvalResult = await this.ensureApproval(tokenIn, amountIn, this.routerAddress);

    const tx = await this.router.swapExactTokensForTokens(
      amountIn,
      amountOutMin,
      swapPath,
      recipient,
      deadline
    );

    const receipt = await tx.wait();

    return {
      approval: approvalResult,
      tx,
      receipt
    };
  }

  async parseAmount(tokenAddress, humanAmount) {
    const { decimals } = await this.getTokenMeta(tokenAddress);
    return ethers.parseUnits(String(humanAmount), decimals);
  }

  async formatAmount(tokenAddress, rawAmount) {
    const { decimals } = await this.getTokenMeta(tokenAddress);
    return ethers.formatUnits(rawAmount, decimals);
  }
}

export async function createSwapInterface({
  routerAddress,
  tokenInAddress,
  tokenOutAddress,
  amountInHuman,
  slippageBps = 50
}) {
  const app = await TokenSwapDApp.fromBrowserWallet(routerAddress);

  const amountIn = await app.parseAmount(tokenInAddress, amountInHuman);
  const amountsOut = await app.getQuote(amountIn, [tokenInAddress, tokenOutAddress]);
  const expectedOut = amountsOut[amountsOut.length - 1];
  const amountOutMin = expectedOut - (expectedOut * BigInt(slippageBps)) / 10000n;

  return {
    app,
    quote: {
      amountIn,
      expectedOut,
      amountOutMin
    },
    async approve() {
      return await app.approveMax(tokenInAddress, routerAddress);
    },
    async swap() {
      return await app.swapExactTokensForTokens({
        tokenIn: tokenInAddress,
        tokenOut: tokenOutAddress,
        amountIn,
        amountOutMin
      });
    }
  };
}